mapper.select:
select *
from inventory_adjustment_review_request

    and review_status = #{reviewStatus}
    and review_no = #{reviewNo}
    and seller_id = #{sellerId}
    and sku_id = #{skuId}
    and stock_id = #{stockId}
    and adjust_direction = #{adjustDirection}

        and concat_ws(' ', review_no, system_sku_code, product_name, sku_name, warehouse_name)
            like concat('%', #{keyword}, '%')

    and submit_time >= #{submitTimeStart}
    and submit_time <= #{submitTimeEnd}

        and planned_effective_time >= #{plannedEffectiveTimeStart}


        and planned_effective_time <= #{plannedEffectiveTimeEnd}


order by submit_time desc, review_id desc

select *
from inventory_adjustment_review_policy

    and policy_name like concat('%', #{policyName}, '%')
    and policy_status = #{policyStatus}
    and review_mode = #{reviewMode}

order by policy_id asc

select b.*, p.policy_name
from inventory_adjustment_review_policy_binding b
left join inventory_adjustment_review_policy p on p.policy_id = b.policy_id

    and b.policy_id = #{policyId}
    and b.binding_type = #{bindingType}
    and b.binding_id_value = #{bindingIdValue}
    and b.status = #{status}

order by b.priority asc, b.binding_id asc

mapper.insert:
insert into inventory_adjustment_review_policy_binding(
    policy_id, binding_type, binding_id_value, priority, status, create_by, create_time, remark
) values (
    #{policyId}, #{bindingType}, #{bindingIdValue}, #{priority}, #{status}, #{createBy}, sysdate(),
    coalesce(#{remark}, '')
)
